# topic_restriction.py
from dataclasses import dataclass
from typing import Optional
import numpy as np

# In production, use a real embedding model.
# Here we mock it to keep the example runnable.
class MockEmbedder:
    """Replace with sentence-transformers or an API-backed embedder."""
    def __init__(self):
        import hashlib, struct
        self._rng = np.random.default_rng(42)

    def embed(self, text: str) -> np.ndarray:
        # Deterministic pseudo-embedding for illustration only
        seed = int(hashlib.md5(text.encode()).hexdigest()[:8], 16)
        rng = np.random.default_rng(seed)
        return rng.standard_normal(384).astype(np.float32)

    def embed_batch(self, texts: list[str]) -> np.ndarray:
        return np.stack([self.embed(t) for t in texts])


@dataclass
class TopicDecision:
    allowed: bool
    matched_topic: Optional[str]  # None if rejected
    confidence: float             # cosine similarity of best match
    rejection_message: Optional[str] = None


class TopicRestrictor:
    """
    Embedding-based topic restriction gate.

    allowed_topics: dict mapping topic name to a list of exemplar strings.
    threshold: minimum cosine similarity for a query to be admitted.
    reject_messages: optional per-topic-category rejection messages.
    """

    def __init__(
        self,
        allowed_topics: dict[str, list[str]],
        threshold: float = 0.72,
        reject_messages: Optional[dict[str, str]] = None,
        default_reject_msg: str = (
            "I can only assist with questions in my supported areas. "
            "Please contact support for further help."
        ),
    ):
        self.threshold = threshold
        self.default_reject_msg = default_reject_msg
        self.reject_messages = reject_messages or {}
        self._embedder = MockEmbedder()

        # Pre-compute and average exemplar embeddings per topic
        self._topic_centroids: dict[str, np.ndarray] = {}
        for topic, exemplars in allowed_topics.items():
            embeddings = self._embedder.embed_batch(exemplars)
            centroid = embeddings.mean(axis=0)
            self._topic_centroids[topic] = centroid / np.linalg.norm(centroid)

    def _cosine_similarity(self, a: np.ndarray, b: np.ndarray) -> float:
        return float(np.dot(a / np.linalg.norm(a), b))

    def check(self, query: str) -> TopicDecision:
        query_emb = self._embedder.embed(query)
        query_emb_norm = query_emb / np.linalg.norm(query_emb)

        best_topic: Optional[str] = None
        best_score = -1.0

        for topic, centroid in self._topic_centroids.items():
            score = float(np.dot(query_emb_norm, centroid))
            if score > best_score:
                best_score = score
                best_topic = topic

        if best_score >= self.threshold:
            return TopicDecision(
                allowed=True,
                matched_topic=best_topic,
                confidence=best_score,
            )
        else:
            reject_msg = self.reject_messages.get(
                best_topic or "", self.default_reject_msg
            )
            return TopicDecision(
                allowed=False,
                matched_topic=None,
                confidence=best_score,
                rejection_message=reject_msg,
            )


# --- Usage ---
if __name__ == "__main__":
    restrictor = TopicRestrictor(
        allowed_topics={
            "billing": [
                "How do I update my payment method?",
                "Why was I charged twice this month?",
                "Can I get a refund for the last invoice?",
                "What is my current subscription plan?",
            ],
            "technical_support": [
                "The app crashes when I open settings.",
                "How do I reset my password?",
                "I can't connect to the API.",
                "Where can I find the SDK documentation?",
            ],
        },
        threshold=0.72,
        reject_messages={
            "billing": "For legal or compliance questions, please contact our legal team.",
            "technical_support": "For medical questions, please consult a healthcare provider.",
        },
    )

    test_queries = [
        "What is my outstanding balance?",           # in-scope: billing
        "How do I fix the login error?",              # in-scope: technical_support
        "What medications interact with your product?",  # out-of-scope: medical
        "Can you recommend a competitor product?",    # out-of-scope: competitor
    ]

    for q in test_queries:
        decision = restrictor.check(q)
        status = "ALLOW" if decision.allowed else "REJECT"
        print(f"[{status}] topic={decision.matched_topic!r} "
              f"conf={decision.confidence:.3f} | {q[:50]}")

# insurance_topic_guard.py -- production-style two-stage implementation
import re
from dataclasses import dataclass
from typing import Optional

HARD_BLOCK_PATTERNS = re.compile(
    r"\b(sue|lawsuit|attorney|legal action|legal advice|"
    r"prescribe|prescription|diagnosis|diagnose|treatment plan|medical advice)\b",
    re.IGNORECASE,
)

ALLOWED_TOPIC_REDIRECTS = {
    "legal": (
        "For questions about disputes, legal rights, or regulatory matters, "
        "please visit our Legal Support portal at support.example.com/legal "
        "or call 1-800-555-LEGAL."
    ),
    "medical": (
        "For medical advice related to your claim, please contact our "
        "24/7 nurse line at 1-800-555-NURSE."
    ),
    "default": (
        "I'm here to help with policy coverage, claims filing, and "
        "premium questions. For other topics, please contact us directly."
    ),
}


@dataclass
class GuardResult:
    allowed: bool
    stage: str  # 'keyword' | 'embedding' | 'passed'
    redirect_message: Optional[str] = None


def classify_topic_category(query: str) -> str:
    """Placeholder: in production this calls the embedding classifier."""
    if any(w in query.lower() for w in ["sue", "court", "attorney"]):
        return "legal"
    if any(w in query.lower() for w in ["doctor", "pain", "treatment"]):
        return "medical"
    return "default"


def insurance_topic_guard(query: str) -> GuardResult:
    # Stage 1: keyword hard block
    if HARD_BLOCK_PATTERNS.search(query):
        category = classify_topic_category(query)
        return GuardResult(
            allowed=False,
            stage="keyword",
            redirect_message=ALLOWED_TOPIC_REDIRECTS.get(
                category, ALLOWED_TOPIC_REDIRECTS["default"]
            ),
        )

    # Stage 2: embedding similarity (mocked here)
    embedding_score = 0.80  # Replace with real classifier call
    if embedding_score < 0.74:
        return GuardResult(
            allowed=False,
            stage="embedding",
            redirect_message=ALLOWED_TOPIC_REDIRECTS["default"],
        )

    return GuardResult(allowed=True, stage="passed")


if __name__ == "__main__":
    tests = [
        "What does my home policy cover for water damage?",  # allowed
        "Can I sue the contractor who caused the damage?",   # blocked: legal
        "My doctor says I need surgery — is that covered?",  # blocked: medical
    ]
    for q in tests:
        result = insurance_topic_guard(q)
        print(f"[{'ALLOW' if result.allowed else 'BLOCK'}/{result.stage}] {q[:60]}")
        if result.redirect_message:
            print(f"  -> {result.redirect_message[:80]}...")

